def solve(*args):
    if not args:
        return None

    # Assuming args is a list of scores
    scores = list(map(int, args))

    if len(scores) == 0:
        return None

    total_score = sum(scores)
    average_score = total_score / len(scores)

    return {
        'total': total_score,
        'average': average_score,
        'count': len(scores)
    }
